import api from '@/apis/BaseApi';
import { SharedMemberGroup } from './models/MemberGroupModel';
import { SharedQuizGroup } from './models/QuizGroupModel';
import { ResourceType } from './models/ShareMappingModel';

export default class ShareMappingApi {
  static async getQuizGroups(): Promise<SharedQuizGroup[]> {
    const result = await api.get('share/quiz-groups');
    return result.data.sharedResources;
  }

  static async getMemberGroups(): Promise<SharedMemberGroup[]> {
    const result = await api.get('share/member-groups');
    return result.data.sharedResources;
  }

  static async list(resourceType: ResourceType): Promise<(SharedQuizGroup|SharedMemberGroup)[]> {
    const result = await api.get(`share/${resourceType}`);
    return result.data.sharedResources;
  }
}
